import{A as e,d as t,m as n,t as r}from"./plugin-vue_export-helper--IMkQmEh.js";var i=JSON.parse(`{"path":"/api-reference.html","title":"GoSwiftKV API 参考手册","lang":"zh-CN","frontmatter":{},"git":{"updatedTime":1773129064000,"contributors":[{"name":"strings77wzq","username":"strings77wzq","email":"strings77wzq@github.com","commits":1,"url":"https://github.com/strings77wzq"}],"changelog":[{"hash":"8ffa3c030f4e1a89621269471e8a91cab0166582","time":1773129064000,"email":"strings77wzq@github.com","author":"strings77wzq","message":"feat: initial commit - Go high-performance Redis-compatible KV store"}]},"filePathRelative":"api-reference.md"}`),a={name:`api-reference.md`};function o(r,i,a,o,s,c){return e(),t(`div`,null,[...i[0]||=[n(`<h1 id="goswiftkv-api-参考手册" tabindex="-1"><a class="header-anchor" href="#goswiftkv-api-参考手册"><span>GoSwiftKV API 参考手册</span></a></h1><h2 id="目录" tabindex="-1"><a class="header-anchor" href="#目录"><span>目录</span></a></h2><ul><li><a href="#%E8%BF%9E%E6%8E%A5%E5%91%BD%E4%BB%A4">连接命令</a></li><li><a href="#%E5%AD%97%E7%AC%A6%E4%B8%B2%E5%91%BD%E4%BB%A4">字符串命令</a></li><li><a href="#%E9%94%AE%E5%91%BD%E4%BB%A4">键命令</a></li><li><a href="#%E6%9C%8D%E5%8A%A1%E5%99%A8%E5%91%BD%E4%BB%A4">服务器命令</a></li></ul><hr><h2 id="连接命令" tabindex="-1"><a class="header-anchor" href="#连接命令"><span>连接命令</span></a></h2><h3 id="ping" tabindex="-1"><a class="header-anchor" href="#ping"><span>PING</span></a></h3><p>测试服务器连接是否正常。</p><p><strong>语法</strong></p><div class="language-text line-numbers-mode" data-highlighter="prismjs" data-ext="text"><pre><code class="language-text"><span class="line">PING [message]</span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><p><strong>返回值</strong></p><ul><li>未指定 message：<code>PONG</code></li><li>指定 message：返回 message 内容</li></ul><p><strong>示例</strong></p><div class="language-bash line-numbers-mode" data-highlighter="prismjs" data-ext="sh"><pre><code class="language-bash"><span class="line">redis-cli <span class="token function">ping</span></span>
<span class="line"><span class="token comment"># PONG</span></span>
<span class="line"></span>
<span class="line">redis-cli <span class="token function">ping</span> <span class="token string">&quot;hello&quot;</span></span>
<span class="line"><span class="token comment"># &quot;hello&quot;</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><hr><h2 id="字符串命令" tabindex="-1"><a class="header-anchor" href="#字符串命令"><span>字符串命令</span></a></h2><h3 id="set" tabindex="-1"><a class="header-anchor" href="#set"><span>SET</span></a></h3><p>设置指定 key 的值。</p><p><strong>语法</strong></p><div class="language-text line-numbers-mode" data-highlighter="prismjs" data-ext="text"><pre><code class="language-text"><span class="line">SET key value</span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><p><strong>返回值</strong></p><ul><li>成功：<code>OK</code></li></ul><p><strong>示例</strong></p><div class="language-bash line-numbers-mode" data-highlighter="prismjs" data-ext="sh"><pre><code class="language-bash"><span class="line">redis-cli <span class="token builtin class-name">set</span> mykey <span class="token string">&quot;myvalue&quot;</span></span>
<span class="line"><span class="token comment"># OK</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div></div></div><hr><h3 id="get" tabindex="-1"><a class="header-anchor" href="#get"><span>GET</span></a></h3><p>获取指定 key 的值。</p><p><strong>语法</strong></p><div class="language-text line-numbers-mode" data-highlighter="prismjs" data-ext="text"><pre><code class="language-text"><span class="line">GET key</span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><p><strong>返回值</strong></p><ul><li>key 存在：返回 value</li><li>key 不存在：返回 <code>nil</code></li></ul><p><strong>示例</strong></p><div class="language-bash line-numbers-mode" data-highlighter="prismjs" data-ext="sh"><pre><code class="language-bash"><span class="line">redis-cli get mykey</span>
<span class="line"><span class="token comment"># &quot;myvalue&quot;</span></span>
<span class="line"></span>
<span class="line">redis-cli get nonexistent</span>
<span class="line"><span class="token comment"># (nil)</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><hr><h3 id="setnx" tabindex="-1"><a class="header-anchor" href="#setnx"><span>SETNX</span></a></h3><p>仅在 key 不存在时设置值。</p><p><strong>语法</strong></p><div class="language-text line-numbers-mode" data-highlighter="prismjs" data-ext="text"><pre><code class="language-text"><span class="line">SETNX key value</span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><p><strong>返回值</strong></p><ul><li>设置成功：<code>1</code></li><li>key 已存在：<code>0</code></li></ul><p><strong>示例</strong></p><div class="language-bash line-numbers-mode" data-highlighter="prismjs" data-ext="sh"><pre><code class="language-bash"><span class="line">redis-cli setnx mykey <span class="token string">&quot;newvalue&quot;</span></span>
<span class="line"><span class="token comment"># (integer) 0  # 已存在，未设置</span></span>
<span class="line"></span>
<span class="line">redis-cli setnx newkey <span class="token string">&quot;value&quot;</span></span>
<span class="line"><span class="token comment"># (integer) 1  # 设置成功</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><hr><h3 id="setex" tabindex="-1"><a class="header-anchor" href="#setex"><span>SETEX</span></a></h3><p>设置 key-value 并指定过期时间（秒）。</p><p><strong>语法</strong></p><div class="language-text line-numbers-mode" data-highlighter="prismjs" data-ext="text"><pre><code class="language-text"><span class="line">SETEX key seconds value</span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><p><strong>返回值</strong></p><ul><li>成功：<code>OK</code></li></ul><p><strong>示例</strong></p><div class="language-bash line-numbers-mode" data-highlighter="prismjs" data-ext="sh"><pre><code class="language-bash"><span class="line">redis-cli setex tempkey <span class="token number">60</span> <span class="token string">&quot;expires in 60s&quot;</span></span>
<span class="line"><span class="token comment"># OK</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div></div></div><hr><h3 id="psetex" tabindex="-1"><a class="header-anchor" href="#psetex"><span>PSETEX</span></a></h3><p>设置 key-value 并指定过期时间（毫秒）。</p><p><strong>语法</strong></p><div class="language-text line-numbers-mode" data-highlighter="prismjs" data-ext="text"><pre><code class="language-text"><span class="line">PSETEX key milliseconds value</span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><p><strong>返回值</strong></p><ul><li>成功：<code>OK</code></li></ul><p><strong>示例</strong></p><div class="language-bash line-numbers-mode" data-highlighter="prismjs" data-ext="sh"><pre><code class="language-bash"><span class="line">redis-cli psetex tempkey <span class="token number">5000</span> <span class="token string">&quot;expires in 5s&quot;</span></span>
<span class="line"><span class="token comment"># OK</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div></div></div><hr><h3 id="mset" tabindex="-1"><a class="header-anchor" href="#mset"><span>MSET</span></a></h3><p>批量设置多个 key-value。</p><p><strong>语法</strong></p><div class="language-text line-numbers-mode" data-highlighter="prismjs" data-ext="text"><pre><code class="language-text"><span class="line">MSET key1 value1 [key2 value2 ...]</span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><p><strong>返回值</strong></p><ul><li>成功：<code>OK</code></li></ul><p><strong>示例</strong></p><div class="language-bash line-numbers-mode" data-highlighter="prismjs" data-ext="sh"><pre><code class="language-bash"><span class="line">redis-cli mset key1 value1 key2 value2 key3 value3</span>
<span class="line"><span class="token comment"># OK</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div></div></div><hr><h3 id="mget" tabindex="-1"><a class="header-anchor" href="#mget"><span>MGET</span></a></h3><p>批量获取多个 key 的值。</p><p><strong>语法</strong></p><div class="language-text line-numbers-mode" data-highlighter="prismjs" data-ext="text"><pre><code class="language-text"><span class="line">MGET key1 [key2 ...]</span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><p><strong>返回值</strong></p><ul><li>返回数组，key 不存在则对应位置为 <code>nil</code></li></ul><p><strong>示例</strong></p><div class="language-bash line-numbers-mode" data-highlighter="prismjs" data-ext="sh"><pre><code class="language-bash"><span class="line">redis-cli mget key1 key2 key3 nonexistent</span>
<span class="line"><span class="token comment"># 1) &quot;value1&quot;</span></span>
<span class="line"><span class="token comment"># 2) &quot;value2&quot;</span></span>
<span class="line"><span class="token comment"># 3) &quot;value3&quot;</span></span>
<span class="line"><span class="token comment"># 4) (nil)</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><hr><h3 id="incr" tabindex="-1"><a class="header-anchor" href="#incr"><span>INCR</span></a></h3><p>将 key 中存储的数字值加一。</p><p><strong>语法</strong></p><div class="language-text line-numbers-mode" data-highlighter="prismjs" data-ext="text"><pre><code class="language-text"><span class="line">INCR key</span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><p><strong>返回值</strong></p><ul><li>返回递增后的值</li><li>key 不存在则初始化为 0 后递增</li><li>值不是整数则返回错误</li></ul><p><strong>示例</strong></p><div class="language-bash line-numbers-mode" data-highlighter="prismjs" data-ext="sh"><pre><code class="language-bash"><span class="line">redis-cli <span class="token builtin class-name">set</span> counter <span class="token number">10</span></span>
<span class="line">redis-cli incr counter</span>
<span class="line"><span class="token comment"># (integer) 11</span></span>
<span class="line"></span>
<span class="line">redis-cli incr newcounter</span>
<span class="line"><span class="token comment"># (integer) 1  # 不存在，从 0 递增</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><hr><h3 id="decr" tabindex="-1"><a class="header-anchor" href="#decr"><span>DECR</span></a></h3><p>将 key 中存储的数字值减一。</p><p><strong>语法</strong></p><div class="language-text line-numbers-mode" data-highlighter="prismjs" data-ext="text"><pre><code class="language-text"><span class="line">DECR key</span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><p><strong>返回值</strong></p><ul><li>返回递减后的值</li></ul><p><strong>示例</strong></p><div class="language-bash line-numbers-mode" data-highlighter="prismjs" data-ext="sh"><pre><code class="language-bash"><span class="line">redis-cli <span class="token builtin class-name">set</span> counter <span class="token number">10</span></span>
<span class="line">redis-cli decr counter</span>
<span class="line"><span class="token comment"># (integer) 9</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><hr><h3 id="incrby" tabindex="-1"><a class="header-anchor" href="#incrby"><span>INCRBY</span></a></h3><p>将 key 中存储的数字值增加指定增量。</p><p><strong>语法</strong></p><div class="language-text line-numbers-mode" data-highlighter="prismjs" data-ext="text"><pre><code class="language-text"><span class="line">INCRBY key increment</span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><p><strong>返回值</strong></p><ul><li>返回递增后的值</li></ul><p><strong>示例</strong></p><div class="language-bash line-numbers-mode" data-highlighter="prismjs" data-ext="sh"><pre><code class="language-bash"><span class="line">redis-cli <span class="token builtin class-name">set</span> counter <span class="token number">10</span></span>
<span class="line">redis-cli incrby counter <span class="token number">5</span></span>
<span class="line"><span class="token comment"># (integer) 15</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><hr><h3 id="decrby" tabindex="-1"><a class="header-anchor" href="#decrby"><span>DECRBY</span></a></h3><p>将 key 中存储的数字值减少指定减量。</p><p><strong>语法</strong></p><div class="language-text line-numbers-mode" data-highlighter="prismjs" data-ext="text"><pre><code class="language-text"><span class="line">DECRBY key decrement</span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><p><strong>返回值</strong></p><ul><li>返回递减后的值</li></ul><p><strong>示例</strong></p><div class="language-bash line-numbers-mode" data-highlighter="prismjs" data-ext="sh"><pre><code class="language-bash"><span class="line">redis-cli <span class="token builtin class-name">set</span> counter <span class="token number">10</span></span>
<span class="line">redis-cli decrby counter <span class="token number">3</span></span>
<span class="line"><span class="token comment"># (integer) 7</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><hr><h3 id="append" tabindex="-1"><a class="header-anchor" href="#append"><span>APPEND</span></a></h3><p>将 value 追加到 key 原有值的末尾。</p><p><strong>语法</strong></p><div class="language-text line-numbers-mode" data-highlighter="prismjs" data-ext="text"><pre><code class="language-text"><span class="line">APPEND key value</span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><p><strong>返回值</strong></p><ul><li>返回追加后的字符串长度</li></ul><p><strong>示例</strong></p><div class="language-bash line-numbers-mode" data-highlighter="prismjs" data-ext="sh"><pre><code class="language-bash"><span class="line">redis-cli <span class="token builtin class-name">set</span> mykey <span class="token string">&quot;Hello&quot;</span></span>
<span class="line">redis-cli append mykey <span class="token string">&quot; World&quot;</span></span>
<span class="line"><span class="token comment"># (integer) 11</span></span>
<span class="line"></span>
<span class="line">redis-cli get mykey</span>
<span class="line"><span class="token comment"># &quot;Hello World&quot;</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><hr><h3 id="strlen" tabindex="-1"><a class="header-anchor" href="#strlen"><span>STRLEN</span></a></h3><p>返回 key 所储存的字符串值的长度。</p><p><strong>语法</strong></p><div class="language-text line-numbers-mode" data-highlighter="prismjs" data-ext="text"><pre><code class="language-text"><span class="line">STRLEN key</span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><p><strong>返回值</strong></p><ul><li>返回字符串长度</li><li>key 不存在返回 0</li></ul><p><strong>示例</strong></p><div class="language-bash line-numbers-mode" data-highlighter="prismjs" data-ext="sh"><pre><code class="language-bash"><span class="line">redis-cli <span class="token builtin class-name">set</span> mykey <span class="token string">&quot;Hello World&quot;</span></span>
<span class="line">redis-cli strlen mykey</span>
<span class="line"><span class="token comment"># (integer) 11</span></span>
<span class="line"></span>
<span class="line">redis-cli strlen nonexistent</span>
<span class="line"><span class="token comment"># (integer) 0</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><hr><h2 id="键命令" tabindex="-1"><a class="header-anchor" href="#键命令"><span>键命令</span></a></h2><h3 id="del" tabindex="-1"><a class="header-anchor" href="#del"><span>DEL</span></a></h3><p>删除一个或多个 key。</p><p><strong>语法</strong></p><div class="language-text line-numbers-mode" data-highlighter="prismjs" data-ext="text"><pre><code class="language-text"><span class="line">DEL key1 [key2 ...]</span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><p><strong>返回值</strong></p><ul><li>返回被删除 key 的数量</li></ul><p><strong>示例</strong></p><div class="language-bash line-numbers-mode" data-highlighter="prismjs" data-ext="sh"><pre><code class="language-bash"><span class="line">redis-cli <span class="token builtin class-name">set</span> key1 value1</span>
<span class="line">redis-cli <span class="token builtin class-name">set</span> key2 value2</span>
<span class="line">redis-cli del key1 key2 key3</span>
<span class="line"><span class="token comment"># (integer) 2  # 删除了 key1 和 key2</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><hr><h3 id="exists" tabindex="-1"><a class="header-anchor" href="#exists"><span>EXISTS</span></a></h3><p>检查一个或多个 key 是否存在。</p><p><strong>语法</strong></p><div class="language-text line-numbers-mode" data-highlighter="prismjs" data-ext="text"><pre><code class="language-text"><span class="line">EXISTS key1 [key2 ...]</span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><p><strong>返回值</strong></p><ul><li>返回存在的 key 数量</li></ul><p><strong>示例</strong></p><div class="language-bash line-numbers-mode" data-highlighter="prismjs" data-ext="sh"><pre><code class="language-bash"><span class="line">redis-cli <span class="token builtin class-name">set</span> key1 value1</span>
<span class="line">redis-cli exists key1 key2 key3</span>
<span class="line"><span class="token comment"># (integer) 1  # 只有 key1 存在</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><hr><h2 id="服务器命令" tabindex="-1"><a class="header-anchor" href="#服务器命令"><span>服务器命令</span></a></h2><h3 id="bgsave" tabindex="-1"><a class="header-anchor" href="#bgsave"><span>BGSAVE</span></a></h3><p>在后台异步保存当前数据库到磁盘。</p><p><strong>语法</strong></p><div class="language-text line-numbers-mode" data-highlighter="prismjs" data-ext="text"><pre><code class="language-text"><span class="line">BGSAVE</span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><p><strong>返回值</strong></p><ul><li>成功：<code>OK</code></li></ul><p><strong>示例</strong></p><div class="language-bash line-numbers-mode" data-highlighter="prismjs" data-ext="sh"><pre><code class="language-bash"><span class="line">redis-cli bgsave</span>
<span class="line"><span class="token comment"># OK</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div></div></div><hr><h2 id="错误响应格式" tabindex="-1"><a class="header-anchor" href="#错误响应格式"><span>错误响应格式</span></a></h2><h3 id="常见错误" tabindex="-1"><a class="header-anchor" href="#常见错误"><span>常见错误</span></a></h3><table><thead><tr><th>错误信息</th><th>说明</th></tr></thead><tbody><tr><td><code>ERR unknown command &#39;xxx&#39;</code></td><td>未知命令</td></tr><tr><td><code>ERR wrong number of arguments for &#39;xxx&#39; command</code></td><td>参数数量错误</td></tr><tr><td><code>WRONGTYPE Operation against a key holding the wrong kind of value</code></td><td>类型错误</td></tr><tr><td><code>ERR value is not an integer</code></td><td>值不是整数</td></tr></tbody></table><hr><h2 id="兼容性说明" tabindex="-1"><a class="header-anchor" href="#兼容性说明"><span>兼容性说明</span></a></h2><p>GoSwiftKV 当前支持以下 Redis 命令：</p><table><thead><tr><th>类别</th><th>命令</th></tr></thead><tbody><tr><td>字符串</td><td>SET, GET, SETNX, SETEX, PSETEX, MSET, MGET, INCR, DECR, INCRBY, DECRBY, APPEND, STRLEN</td></tr><tr><td>键</td><td>DEL, EXISTS</td></tr><tr><td>连接</td><td>PING</td></tr><tr><td>服务器</td><td>BGSAVE</td></tr></tbody></table><p><strong>计划支持</strong>：Hash, List, Set, ZSet, Pub/Sub, 事务等。</p><hr><h2 id="版本" tabindex="-1"><a class="header-anchor" href="#版本"><span>版本</span></a></h2><ul><li>文档版本：v0.1.0</li><li>兼容 Redis 协议版本：RESP2</li></ul>`,172)]])}var s=r(a,[[`render`,o]]);export{i as _pageData,s as default};